import { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';

function Navbar() {
  const navigate = useNavigate();
  const location = useLocation();
  const [open, setOpen] = useState(false);
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user') || '{}');
  const isActive = (p) => location.pathname === p;

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  return (
    <nav style={{
      background: 'rgba(253,246,243,0.95)', backdropFilter: 'blur(20px)',
      borderBottom: '1px solid #f0ddd7', position: 'sticky', top: 0, zIndex: 100,
      padding: '0 2rem', boxShadow: '0 2px 20px rgba(201,169,154,0.15)'
    }}>
      <div style={{ maxWidth: '1300px', margin: '0 auto', display: 'flex', justifyContent: 'space-between', alignItems: 'center', height: '68px' }}>

        {/* Logo */}
        <Link to={token ? '/home' : '/'} style={{ display: 'flex', alignItems: 'center', gap: '10px', textDecoration: 'none' }}>
          <div style={{ width: '36px', height: '36px', background: 'linear-gradient(135deg, #c9a99a, #e8c4b8)', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.1rem' }}>🌸</div>
          <span style={{ color: '#2d1f1f', fontWeight: '700', fontSize: '1.2rem', fontFamily: "'Cormorant Garamond', serif", letterSpacing: '0.5px' }}>
            Event<span style={{ color: '#c9a99a' }}>Hub</span>
          </span>
        </Link>

        {/* Links */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          {token ? (
            <>
              {[
                { to: '/home', label: 'Home' },
                { to: '/my-bookings', label: 'My Bookings' },
              ].map(link => (
                <Link key={link.to} to={link.to} style={{
                  color: isActive(link.to) ? '#c9a99a' : '#6b5a55',
                  textDecoration: 'none', padding: '8px 16px', borderRadius: '20px',
                  fontSize: '0.85rem', fontWeight: '500', transition: 'all 0.2s',
                  background: isActive(link.to) ? '#fdeee9' : 'transparent'
                }}>{link.label}</Link>
              ))}
              {user.role === 'admin' && (
                <Link to="/admin" style={{ color: '#c9a99a', textDecoration: 'none', padding: '8px 16px', borderRadius: '20px', fontSize: '0.85rem', fontWeight: '500', background: isActive('/admin') ? '#fdeee9' : 'transparent' }}>Admin</Link>
              )}
              <span style={{ background: '#fdeee9', color: '#c9a99a', padding: '8px 16px', borderRadius: '20px', fontSize: '0.82rem', fontWeight: '600', border: '1px solid #f0ddd7' }}>
                🌸 {user.name}
              </span>
              <button onClick={handleLogout} style={{ background: '#2d1f1f', color: 'white', border: 'none', padding: '8px 20px', borderRadius: '20px', cursor: 'pointer', fontSize: '0.82rem', fontWeight: '600' }}>
                Logout
              </button>
            </>
          ) : (
            <>
              <Link to="/login" style={{ color: '#6b5a55', textDecoration: 'none', padding: '8px 16px', borderRadius: '20px', fontSize: '0.85rem' }}>Login</Link>
              <Link to="/register" style={{ background: 'linear-gradient(135deg, #c9a99a, #e8c4b8)', color: 'white', padding: '9px 22px', borderRadius: '20px', textDecoration: 'none', fontSize: '0.85rem', fontWeight: '600', boxShadow: '0 4px 15px rgba(201,169,154,0.4)' }}>Sign Up Free</Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}
export default Navbar;
